let urlRequest = Endpoint().urlRequest
        let session = Session()

        let retrier = InspectorInterceptor(Retrier { _, _, _, completion in
            completion(.retry)
        })

        // When
        retrier.adapt(urlRequest, for: session) { _ in }

        // Then
        #expect(retrier.adaptations.first?.result.isSuccess == true)
